              { name: "Inverse sinh", expr: "arsinh x = ln(x + √(x²+1))" },
              { name: "Inverse cosh", expr: "arcosh x = ln(x + √(x²-1)), x ≥ 1" },
              { name: "Standard Integral", expr: "∫1/√(x²+a²) dx = arsinh(x/a) + C" }
